rows = d.get('data',[]) if isinstance(d.get('data'), list) else d.get('data',{}).get('data',[])
for r in rows[:2]:
  cat = r.get('category') or {}
  loc = r.get('location') or {}
  dept = r.get('department') or {}
  print(f\"{r['name']}: cat={cat.get('name','NONE')}, loc={loc.get('name','NONE')}, dept={dept.get('name','NONE')}\")
"

